('retirement','tu','moyen',$$Tu as été un collègue incroyable. Bonne retraite, et merc...$$,$$Tu as été un collègue incroyable. Bonne retraite, et merci pour ces souvenirs.$$,true),
('retirement','tu','moyen',$$Maintenant, c’est l’heure des voyages, des passions et de...$$,$$Maintenant, c’est l’heure des voyages, des passions et des grasses mat’. Bonne retraite ! ☕$$,true),
